  value: string
  native?: boolean
}
```

#### **GeneratorOptions** (Data available in onGenerate)
```typescript
export type GeneratorOptions = {
  generator: GeneratorConfig
  otherGenerators: GeneratorConfig[]
  schemaPath: string
  dmmf: DMMF.Document
  datasources: DataSource[]
  datamodel: string
  version: string // version hash
  binaryPaths?: BinaryPaths
  noHints?: boolean
  allowNoModels?: boolean
  typedSql?: SqlQueryOutput[]
}
```

#### **DataSource**
```typescript
export interface DataSource {
  name: string
  provider: ConnectorType
  activeProvider: ActiveConnectorType
  schemas: string[] | []
  sourceFilePath: string
}

export type ConnectorType =
  | 'mysql'
  | 'mongodb'
  | 'sqlite'
  | 'postgresql'
  | 'postgres'
  | 'prisma+postgres'
  | 'sqlserver'
  | 'cockroachdb'
```

---

### 2. **Generator Interface** (`packages/generator/src/generator.ts`)

```typescript
export type Generator = {
  readonly name: string
  getManifest(config: GeneratorConfig): Promise<GeneratorManifest>
  generate(options: GeneratorOptions): Promise<void>
}
```

---

### 3. **Handler Protocol** (`packages/generator-helper/src/generatorHandler.ts`)

The `generatorHandler` function is the entry point that handles JSON-RPC communication from the Prisma CLI. It accepts a `Handler` object:

```typescript
export interface Handler {
  onGenerate(options: GeneratorOptions): Promise<any>
  onManifest?(config: GeneratorConfig): GeneratorManifest | Promise<GeneratorManifest>
}

export function generatorHandler(handler: Handler): void {
  const stdinInterface = readline.createInterface({
    input: process.stdin,
    crlfDelay: Infinity,
  })

  stdinInterface.on('line', async (line: string) => {
    const json = JSON.parse(line)

    if (json.method === 'generate' && json.params) {
      try {
        const result = await handler.onGenerate(json.params)
        respond({ jsonrpc: '2.0', result, id: json.id })
      } catch (_e) {
        respond({ jsonrpc: '2.0', error: { code: -32000, message: e.message, data: { stack: e.stack } }, id: json.id })
      }
    }

    if (json.method === 'getManifest') {
      // Similar try/catch for onManifest
    }
  })

  process.stdin.resume()
}

function respond(response: JsonRpc.Response): void {
  process.stderr.write(JSON.stringify(response) + '\n')
}
```

**Key Protocol Details:**
- **Input:** JSON-RPC 2.0 messages via stdin (line-by-line)
- **Output:** JSON-RPC 2.0 responses via stderr
- **Methods:** `generate` and `getManifest`
- **Communication:** Non-blocking readline, one JSON object per line

---

### 4. **JSON-RPC Types** (`packages/generator-helper/src/json-rpc.ts`)

```typescript
export type Request = {
  jsonrpc: '2.0'
  method: string
  params?: any
  id: number
}

export type Response = SuccessResponse | ErrorResponse

export type SuccessResponse = {
  jsonrpc: '2.0'
  result: any
  id: number
}

export type ErrorResponse = {
  jsonrpc: '2.0'
  error: {
    code: number
    message: string
    data: any
  }
  id: number
}
```

---

### 5. **DMMF (Data Model Meta Format)** (`packages/dmmf/src/dmmf.ts`)

The DMMF provides the complete schema information. Key structures:

```typescript
export type Document = {
  datamodel: Datamodel
  schema: Schema
  mappings: Mappings
}

export type Datamodel = {
  models: Model[]
  enums: DatamodelEnum[]
  types: Model[]
  indexes: Index[]
}

export type Model = {
  name: string
  dbName: string | null
  schema: string | null
  fields: Field[]
  uniqueFields: string[][]
  uniqueIndexes: uniqueIndex[]
  documentation?: string
  primaryKey: PrimaryKey | null
  isGenerated?: boolean
}

export type Field = {
  kind: 'scalar' | 'object' | 'enum' | 'unsupported'
  name: string
  isRequired: boolean
  isList: boolean
  isUnique: boolean
  isId: boolean
  isReadOnly: boolean
  isGenerated?: boolean
  isUpdatedAt?: boolean
  type: string // e.g., "String", "Int", "$ModelName"
  nativeType?: [string, string[]] | null
  dbName?: string | null
  hasDefaultValue: boolean
  default?: FieldDefault | FieldDefaultScalar | FieldDefaultScalar[]
  relationFromFields?: string[]
  relationToFields?: string[]
  relationOnDelete?: string
  relationOnUpdate?: string
  relationName?: string
