export type Schema = {
  rootQueryType?: string
  rootMutationType?: string
  inputObjectTypes: {
    model?: InputType[]
    prisma?: InputType[]
  }
  outputObjectTypes: {
    model: OutputType[]
    prisma: OutputType[]
  }
  enumTypes: {
    model?: SchemaEnum[]
    prisma: SchemaEnum[]
  }
  fieldRefTypes: {
    prisma?: FieldRefType[]
  }
}

export type Mappings = {
  modelOperations: ModelMapping[]
  otherOperations: {
    read: string[]
    write: string[]
  }
}

export type ModelMapping = {
  model: string
  plural: string
  findUnique?: string | null
  findUniqueOrThrow?: string | null
  findFirst?: string | null
  findFirstOrThrow?: string | null
  findMany?: string | null
  create?: string | null
  createMany?: string | null
  createManyAndReturn?: string | null
  update?: string | null
  updateMany?: string | null
  updateManyAndReturn?: string | null
  upsert?: string | null
  delete?: string | null
  deleteMany?: string | null
  aggregate?: string | null
  groupBy?: string | null
  count?: string | null
  findRaw?: string | null
  aggregateRaw?: string | null
}
```

---

### 6. **Client Generator JS Implementation** 
**File:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775389229566-n145p2/packages/client-generator-js/src/generator.ts`

Implements the `Generator` interface:

```typescript
export class PrismaClientJsGenerator implements Generator {
  readonly name = BuiltInProvider.PrismaClientJs

  async getManifest(config: GeneratorConfig): Promise<GeneratorManifest> {
    return {
      defaultOutput: await this.#getPrismaClientPath(config),
      prettyName: 'Prisma Client',
      version: clientVersion,
      requiresEngines: [],
      requiresEngineVersion: enginesVersion,
    }
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = parseEnvValue(options.generator.output!)
    await generateClient({
      datamodel: options.datamodel,
      schemaPath: options.schemaPath,
      binaryPaths: options.binaryPaths!,
      datasources: options.datasources,
      outputDir,
      dmmf: options.dmmf,
      // ... additional options
    })
  }
}
```

**File generation flow:**
1. `generateClient()` calls `buildClient()` to create a `FileMap`
2. `FileMap` is an object mapping filenames to string content or nested directories
3. `writeFileMap()` recursively writes files to disk
4. Schema file `schema.prisma` is written separately

