---

### 9. **Generator Invocation (IPC)**
**File:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775389229566-n145p2/packages/generator-helper/src/GeneratorProcess.ts`

The CLI spawns generators as child processes:

```typescript
export class GeneratorProcess {
  async init(): Promise<void> {
    this.child = fork(pathOrCommand, [], {
      stdio: ['pipe', 'inherit', 'pipe'],
      env: { ...process.env, PRISMA_GENERATOR_INVOCATION: 'true' },
      execArgv: ['--max-old-space-size=8096'],
    })

    // Listen to stderr for JSON-RPC responses
    const stderrInterface = readline.createInterface({ input: this.child.stderr })
    stderrInterface.on('line', (line: string) => {
      const data = JSON.parse(line)
      this.handleResponse(data)
    })
  }

  getManifest = this.rpcMethod<GeneratorConfig, GeneratorManifest | null>(
    'getManifest',
    (result) => (result as { manifest?: GeneratorManifest | null }).manifest ?? null,
  )

  generate = this.rpcMethod<GeneratorOptions, void>('generate')
}
```

---

### **Summary: Complete API Contract**

