---

## Implementation Plan: `@prisma/generator-rest-client`

### 1. Package File Structure

```
packages/generator-rest-client/
├── package.json
├── tsconfig.json
├── tsconfig.build.json
├── helpers/
│   └── build.ts
└── src/
    ├── index.ts              # Entry point: shebang + generatorHandler()
    ├── generator.ts          # onManifest and onGenerate logic
    ├── dmmf-helpers.ts       # DMMF parsing utilities
    ├── type-mapping.ts       # Prisma scalar -> TypeScript type mapping
    ├── code-generator.ts     # Builds the rest-client.ts string output
    └── __tests__/
        └── generator.test.ts # Unit tests
```

### 2. File-by-File Specification

---

#### 2.1. `packages/generator-rest-client/package.json`

Follow the convention from `@prisma/dmmf` and `@prisma/generator-helper`. Key differences: this package has a `bin` field because the Prisma CLI spawns external generators as child processes.

```json
{
  "name": "@prisma/generator-rest-client",
  "version": "0.0.0",
  "description": "Prisma generator that outputs a typed REST API client",
  "main": "dist/index.js",
  "module": "dist/index.mjs",
  "types": "dist/index.d.ts",
  "bin": {
    "prisma-generator-rest-client": "dist/index.js"
  },
  "exports": {
    ".": {
      "require": {
        "types": "./dist/index.d.ts",
        "default": "./dist/index.js"
      },
      "import": {
        "types": "./dist/index.d.ts",
        "default": "./dist/index.mjs"
      }
    }
  },
  "repository": {
    "type": "git",
    "url": "https://github.com/prisma/prisma.git",
    "directory": "packages/generator-rest-client"
  },
  "license": "Apache-2.0",
  "dependencies": {
    "@prisma/generator-helper": "workspace:*",
    "@prisma/dmmf": "workspace:*",
    "@prisma/generator": "workspace:*"
  },
  "devDependencies": {
    "@types/node": "~20.19.24",
    "typescript": "5.4.5"
  },
  "scripts": {
    "dev": "DEV=true tsx helpers/build.ts",
    "build": "tsx helpers/build.ts",
    "prepublishOnly": "pnpm run build",
    "test": "vitest run"
  },
  "files": [
    "dist"
  ],
  "sideEffects": false
}
```

**Rationale**: The `bin` field maps `prisma-generator-rest-client` to `dist/index.js`. When the user puts `provider = "prisma-generator-rest-client"` in their schema, the Prisma CLI resolves this as a command via `$PATH` (or node_modules/.bin), spawns it as a child process, and communicates via JSON-RPC on stdin/stderr. The built `dist/index.js` must start with `#!/usr/bin/env node`.

---

#### 2.2. `packages/generator-rest-client/tsconfig.json`

```json
{
  "extends": "../../tsconfig.json",
  "include": ["./**/*"]
}
```

#### 2.3. `packages/generator-rest-client/tsconfig.build.json`

```json
{
  "extends": "../../tsconfig.build.regular.json",
  "compilerOptions": {
    "outDir": "dist"
  },
  "include": ["src"]
}
```

#### 2.4. `packages/generator-rest-client/helpers/build.ts`

Use the same pattern as `@prisma/generator-helper`. The generator-helper uses ESM splitting with CJS conversion and bundles from `src/index.ts`. Since this package is a standalone executable, bundling is appropriate. The `@prisma/generator-helper`, `@prisma/dmmf`, and `@prisma/generator` packages are external since they are runtime dependencies.

```ts
import { build } from '../../../helpers/compile/build'
import { esmSplitCodeToCjs } from '../../../helpers/compile/plugins/esmSplitCodeToCjs'

void build([
  {
    name: 'default',
    bundle: true,
    emitTypes: true,
    splitting: true,
    format: 'esm',
    plugins: [esmSplitCodeToCjs],
    external: ['@prisma/generator-helper', '@prisma/dmmf', '@prisma/generator'],
  },
])
```

**Important**: After the build, the `dist/index.js` file must have the `#!/usr/bin/env node` shebang prepended. The entry point `src/index.ts` should include the shebang as a comment or the build process should be configured to add it. Looking at the `packages/cli/package.json` which has `"bin": { "prisma": "build/index.js" }`, the Prisma CLI build injects the shebang. For this package, the simplest approach is to add an esbuild banner:

```ts
void build([
  {
    name: 'default',
    bundle: true,
    emitTypes: true,
    splitting: true,
    format: 'esm',
    plugins: [esmSplitCodeToCjs],
    external: ['@prisma/generator-helper', '@prisma/dmmf', '@prisma/generator'],
    banner: { js: '#!/usr/bin/env node' },
  },
])
```

---

#### 2.5. `packages/generator-rest-client/src/index.ts`

This is the entry point. It registers the generator handler with `generatorHandler()` from `@prisma/generator-helper`. The handler reads JSON-RPC messages from stdin and responds on stderr.

```ts
import { generatorHandler } from '@prisma/generator-helper'
import { onGenerate, onManifest } from './generator'

generatorHandler({
  onManifest,
  onGenerate,
})
```

---

#### 2.6. `packages/generator-rest-client/src/generator.ts`

Contains the two handler callbacks: `onManifest` and `onGenerate`.

```ts
import fs from 'node:fs'
import path from 'node:path'

import type { GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import { generateRestClient } from './code-generator'

export function onManifest(config: GeneratorConfig): GeneratorManifest {
  return {
    defaultOutput: './generated/rest-client',
    prettyName: 'Prisma REST Client',
  }
}

export async function onGenerate(options: GeneratorOptions): Promise<void> {
  const output = options.generator.output
  if (!output || !output.value) {
    throw new Error('No output directory specified for generator-rest-client')
  }

  const outputDir = output.fromEnvVar
    ? process.env[output.fromEnvVar] ?? output.value
    : output.value

  const code = generateRestClient(options.dmmf)

  fs.mkdirSync(outputDir, { recursive: true })
  fs.writeFileSync(path.join(outputDir, 'rest-client.ts'), code, 'utf-8')
}
```

**Key decisions**:
- `defaultOutput` is `./generated/rest-client` relative to the schema file. This follows the convention of `.prisma/client` used by the main generator, but uses a distinct path.
- The output parsing replicates the pattern from `parseEnvValue` in `@prisma/internals` (line 11-27 of that file) but avoids importing `@prisma/internals` as a dependency, since it is a very heavy package. The env var resolution is simple enough to inline.
- The function writes a single file `rest-client.ts` to the output directory.

---

#### 2.7. `packages/generator-rest-client/src/type-mapping.ts`

Maps Prisma scalar type strings (from `DMMF.Field.type`) to TypeScript type strings. These type strings come from the DMMF and are documented in the `Field.type` JSDoc in `/packages/dmmf/src/dmmf.ts` (line 85): `BigInt`, `Boolean`, `Bytes`, `DateTime`, `Decimal`, `Float`, `Int`, `JSON`, `String`.

```ts
const PRISMA_SCALAR_TO_TS: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  Decimal: 'number',
  BigInt: 'bigint',
  DateTime: 'Date',
  JSON: 'unknown',
  Json: 'unknown',
  Bytes: 'Buffer',
}

export function mapScalarType(prismaType: string): string {
  return PRISMA_SCALAR_TO_TS[prismaType] ?? 'unknown'
}
```

**Rationale for mappings**:
- `String` -> `string`: direct mapping
- `Boolean` -> `boolean`: direct mapping
- `Int`, `Float`, `Decimal` -> `number`: REST APIs serialize all numbers as JSON numbers. Unlike the Prisma Client which uses `Prisma.Decimal` for `Decimal`, a REST client receives plain numbers. This is the pragmatic choice for a REST context.
- `BigInt` -> `bigint`: preserves precision intent; the consumer of the REST client will need to handle serialization (e.g., as string in JSON). An alternative is `string`, but `bigint` is the TypeScript convention.
- `DateTime` -> `Date`: REST APIs typically serialize dates as ISO strings, but the generated type uses `Date` since the client would deserialize them. For the `CreateInput` types, `string | Date` could be used, but for simplicity this plan uses `Date` uniformly.
- `JSON`/`Json` -> `unknown`: the JSON field can contain any valid JSON, so `unknown` is the safest type. Both casings are handled because DMMF may use either.
- `Bytes` -> `Buffer`: binary data in Node.js context.

---

#### 2.8. `packages/generator-rest-client/src/dmmf-helpers.ts`

Utility functions to extract structured data from the DMMF for code generation.

```ts
import type * as DMMF from '@prisma/dmmf'

export interface ParsedField {
  name: string
  tsType: string
  isOptional: boolean
  isList: boolean
  isRelation: boolean
  isId: boolean
  isReadOnly: boolean
  hasDefaultValue: boolean
  kind: DMMF.FieldKind
  documentation?: string
}

export interface ParsedModel {
  name: string
  fields: ParsedField[]
  idField: ParsedField | null
  scalarFields: ParsedField[]
  documentation?: string
}

export interface ParsedEnum {
  name: string
  values: string[]
}

export function parseModels(dmmf: DMMF.Document): ParsedModel[] {
  return dmmf.datamodel.models.map((model) => {
    const fields = model.fields.map(parseField)
    return {
      name: model.name,
      fields,
      idField: fields.find((f) => f.isId) ?? null,
      scalarFields: fields.filter((f) => !f.isRelation),
      documentation: model.documentation,
    }
  })
}

export function parseEnums(dmmf: DMMF.Document): ParsedEnum[] {
  return dmmf.datamodel.enums.map((e) => ({
    name: e.name,
    values: e.values.map((v) => v.name),
  }))
}

function parseField(field: DMMF.Field): ParsedField {
  return {
    name: field.name,
    tsType: field.type,  // resolved later by code-generator using type-mapping
    isOptional: !field.isRequired,
    isList: field.isList,
    isRelation: field.kind === 'object',
    isId: field.isId,
    isReadOnly: field.isReadOnly,
    hasDefaultValue: field.hasDefaultValue,
    kind: field.kind,
    documentation: field.documentation,
  }
}
```

**Key design**: The `parseField` function preserves the raw `field.type` string (e.g., `"String"`, `"Int"`, `"User"`, `"Role"`) in `tsType`. The actual TypeScript type resolution is deferred to `code-generator.ts` which uses `type-mapping.ts` for scalars and references enum/model names directly.

---

#### 2.9. `packages/generator-rest-client/src/code-generator.ts`

This is the core module. It takes the parsed DMMF and produces the full `rest-client.ts` file contents as a string.

```ts
import type * as DMMF from '@prisma/dmmf'

import { parseEnums, parseModels, ParsedField, ParsedModel } from './dmmf-helpers'
import { mapScalarType } from './type-mapping'

export function generateRestClient(dmmf: DMMF.Document): string {
  const models = parseModels(dmmf)
  const enums = parseEnums(dmmf)
  const enumNames = new Set(enums.map((e) => e.name))
  const modelNames = new Set(models.map((m) => m.name))

  const parts: string[] = []

  // Header
  parts.push(generateHeader())

  // Enums
  for (const enumDef of enums) {
    parts.push(generateEnum(enumDef))
  }

  // Model interfaces
  for (const model of models) {
    parts.push(generateModelInterface(model, enumNames, modelNames))
  }

  // Create input types (omit id, relations, readOnly fields, fields with defaults)
  for (const model of models) {
    parts.push(generateCreateInput(model, enumNames, modelNames))
  }

  // Update input types (all non-relation scalar fields optional)
  for (const model of models) {
    parts.push(generateUpdateInput(model, enumNames, modelNames))
  }

  // WhereUnique input types (id field only)
  for (const model of models) {
    parts.push(generateWhereUniqueInput(model, enumNames, modelNames))
  }

  // REST client class
  parts.push(generateClientClass(models))

  return parts.join('\n\n')
}
```

Below are the sub-functions. I will detail the signatures and logic for each.

##### `generateHeader()`

```ts
function generateHeader(): string {
  return [
    '// This file was generated by prisma-generator-rest-client. Do not edit manually.',
    '',
    'type RequestOptions = {',
    '  headers?: Record<string, string>',
    '}',
    '',
    'type RestClientConfig = {',
    '  baseUrl: string',
    '  headers?: Record<string, string>',
    '}',
  ].join('\n')
}
```

##### `generateEnum(enumDef)`

```ts
function generateEnum(enumDef: ParsedEnum): string {
  const values = enumDef.values.map((v) => `  ${v} = '${v}'`).join(',\n')
  return `export enum ${enumDef.name} {\n${values}\n}`
}
```

##### `resolveFieldType(field, enumNames, modelNames)`

This is the central type resolution function:

```ts
function resolveFieldType(
  field: ParsedField,
  enumNames: Set<string>,
  modelNames: Set<string>,
): string {
  let tsType: string

  if (field.kind === 'enum') {
    tsType = field.tsType  // use the enum name directly
  } else if (field.kind === 'object') {
    // Relation field — reference the model interface
    tsType = field.tsType
  } else if (field.kind === 'scalar') {
    tsType = mapScalarType(field.tsType)
  } else {
    // 'unsupported'
    tsType = 'unknown'
  }

  if (field.isList) {
    tsType = `${tsType}[]`
  }

  if (field.isOptional) {
    tsType = `${tsType} | null`
  }

  return tsType
}
```

##### `generateModelInterface(model, enumNames, modelNames)`

Generates the full model interface including relation fields:

```ts
function generateModelInterface(
  model: ParsedModel,
  enumNames: Set<string>,
  modelNames: Set<string>,
): string {
  const lines = model.fields.map((field) => {
    const type = resolveFieldType(field, enumNames, modelNames)
    const optionalMark = field.isRelation ? '?' : ''
    const doc = field.documentation ? `  /** ${field.documentation} */\n` : ''
    return `${doc}  ${field.name}${optionalMark}: ${type}`
  })

  const doc = model.documentation ? `/** ${model.documentation} */\n` : ''
  return `${doc}export interface ${model.name} {\n${lines.join('\n')}\n}`
}
```

**Relation field handling**: Relation fields are made optional with `?` on the interface. This is because a REST API response might or might not include related models (they may need a separate request or an `include` parameter). The type reference is the name of the related model's interface directly, so `posts?: Post[]` for a `User` model with a `posts` relation.

##### `generateCreateInput(model, enumNames, modelNames)`

```ts
function generateCreateInput(
  model: ParsedModel,
  enumNames: Set<string>,
  modelNames: Set<string>,
): string {
  const fields = model.fields.filter((f) => {
    // Skip relations, read-only fields, and auto-generated id fields
    if (f.isRelation) return false
    if (f.isReadOnly) return false
    return true
  })

  const lines = fields.map((field) => {
    const type = resolveFieldType(
      { ...field, isOptional: false },
      enumNames,
      modelNames,
    )
    // Fields with defaults or that are optional become optional in CreateInput
    const isOptionalInCreate = field.hasDefaultValue || field.isOptional || field.isId
    const optionalMark = isOptionalInCreate ? '?' : ''
    return `  ${field.name}${optionalMark}: ${type}`
  })

  return `export interface ${model.name}CreateInput {\n${lines.join('\n')}\n}`
}
```

**Rationale**: Fields with `hasDefaultValue` (like auto-increment IDs, `@default(now())`, `@default(uuid())`) are optional in create because the database will supply them. The `isId` check also catches ID fields that have `@default(autoincrement())`. Fields that are `isOptional` (i.e., not `isRequired`) are nullable in the database and therefore optional on create. Relation fields and read-only fields (like foreign key fields marked with `@relation`) are excluded.

##### `generateUpdateInput(model, enumNames, modelNames)`

```ts
function generateUpdateInput(
  model: ParsedModel,
  enumNames: Set<string>,
  modelNames: Set<string>,
): string {
  const fields = model.fields.filter((f) => {
    if (f.isRelation) return false
    if (f.isReadOnly) return false
    if (f.isId) return false
    return true
  })

  const lines = fields.map((field) => {
    const type = resolveFieldType(
      { ...field, isOptional: false },
      enumNames,
      modelNames,
    )
    // All fields optional in update (partial update)
    return `  ${field.name}?: ${type}`
  })

  return `export interface ${model.name}UpdateInput {\n${lines.join('\n')}\n}`
}
```

##### `generateWhereUniqueInput(model, enumNames, modelNames)`

```ts
function generateWhereUniqueInput(
  model: ParsedModel,
  enumNames: Set<string>,
  modelNames: Set<string>,
): string {
  const idField = model.idField
  if (idField) {
    const type = resolveFieldType(
      { ...idField, isOptional: false, isList: false },
      enumNames,
      modelNames,
    )
    return `export interface ${model.name}WhereUniqueInput {\n  ${idField.name}: ${type}\n}`
  }

  // Fallback: if no single @id field, use Record<string, unknown>
  return `export type ${model.name}WhereUniqueInput = Record<string, unknown>`
}
```

##### `generateClientClass(models)`

```ts
function generateClientClass(models: ParsedModel[]): string {
  const modelDelegates = models.map((model) => {
    const name = model.name
    const lowerName = name.charAt(0).toLowerCase() + name.slice(1)
    const pluralName = lowerName + 's'  // simple pluralization

    return `  ${lowerName} = {
    findMany: async (options?: RequestOptions): Promise<${name}[]> => {
      const response = await fetch(\`\${this.baseUrl}/${pluralName}\`, {
        method: 'GET',
        headers: { ...this.headers, ...options?.headers },
      })
      if (!response.ok) throw new Error(\`GET /${pluralName} failed: \${response.statusText}\`)
      return response.json() as Promise<${name}[]>
    },

    findUnique: async (where: ${name}WhereUniqueInput, options?: RequestOptions): Promise<${name} | null> => {
      const id = ${model.idField ? `where.${model.idField.name}` : 'Object.values(where)[0]'}
      const response = await fetch(\`\${this.baseUrl}/${pluralName}/\${id}\`, {
        method: 'GET',
        headers: { ...this.headers, ...options?.headers },
      })
      if (response.status === 404) return null
      if (!response.ok) throw new Error(\`GET /${pluralName}/\${id} failed: \${response.statusText}\`)
      return response.json() as Promise<${name}>
    },

    create: async (data: ${name}CreateInput, options?: RequestOptions): Promise<${name}> => {
      const response = await fetch(\`\${this.baseUrl}/${pluralName}\`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', ...this.headers, ...options?.headers },
        body: JSON.stringify(data),
      })
      if (!response.ok) throw new Error(\`POST /${pluralName} failed: \${response.statusText}\`)
      return response.json() as Promise<${name}>
    },

    update: async (where: ${name}WhereUniqueInput, data: ${name}UpdateInput, options?: RequestOptions): Promise<${name}> => {
      const id = ${model.idField ? `where.${model.idField.name}` : 'Object.values(where)[0]'}
      const response = await fetch(\`\${this.baseUrl}/${pluralName}/\${id}\`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json', ...this.headers, ...options?.headers },
        body: JSON.stringify(data),
      })
      if (!response.ok) throw new Error(\`PATCH /${pluralName}/\${id} failed: \${response.statusText}\`)
      return response.json() as Promise<${name}>
    },

    delete: async (where: ${name}WhereUniqueInput, options?: RequestOptions): Promise<${name}> => {
      const id = ${model.idField ? `where.${model.idField.name}` : 'Object.values(where)[0]'}
      const response = await fetch(\`\${this.baseUrl}/${pluralName}/\${id}\`, {
        method: 'DELETE',
        headers: { ...this.headers, ...options?.headers },
      })
      if (!response.ok) throw new Error(\`DELETE /${pluralName}/\${id} failed: \${response.statusText}\`)
      return response.json() as Promise<${name}>
    },
  }`
  })

  return [
    'export class RestClient {',
    '  private baseUrl: string',
    '  private headers: Record<string, string>',
    '',
    '  constructor(config: RestClientConfig) {',
    '    this.baseUrl = config.baseUrl.replace(/\\/$/, \'\')',
    '    this.headers = config.headers ?? {}',
    '  }',
    '',
    modelDelegates.join('\n\n'),
    '}',
  ].join('\n')
}
```

