### 3. Sample Schema and Generated Output

Given this Prisma schema:

```prisma
datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator rest {
  provider = "prisma-generator-rest-client"
  output   = "./generated/rest-client"
}

enum Role {
  USER
  ADMIN
}

model User {
  id        Int      @id @default(autoincrement())
  email     String   @unique
  name      String?
  role      Role     @default(USER)
  posts     Post[]
  createdAt DateTime @default(now())
}

model Post {
  id        Int      @id @default(autoincrement())
  title     String
  content   String?
  published Boolean  @default(false)
  author    User     @relation(fields: [authorId], references: [id])
  authorId  Int
}
```

The generated `rest-client.ts` would be:

```ts
// This file was generated by prisma-generator-rest-client. Do not edit manually.

type RequestOptions = {
  headers?: Record<string, string>
}

type RestClientConfig = {
  baseUrl: string
  headers?: Record<string, string>
}

export enum Role {
  USER = 'USER',
  ADMIN = 'ADMIN'
}

export interface User {
  id: number
  email: string
  name: string | null
  role: Role
  posts?: Post[]
  createdAt: Date
}

export interface Post {
  id: number
  title: string
  content: string | null
  published: boolean
  author?: User
  authorId: number
}

export interface UserCreateInput {
  id?: number
  email: string
  name?: string
  role?: Role
  createdAt?: Date
}

export interface PostCreateInput {
  id?: number
  title: string
  content?: string
  published?: boolean
  authorId: number
}

export interface UserUpdateInput {
  email?: string
  name?: string
  role?: Role
  createdAt?: Date
}

export interface PostUpdateInput {
  title?: string
  content?: string
  published?: boolean
  authorId?: number
}

export interface UserWhereUniqueInput {
  id: number
}

export interface PostWhereUniqueInput {
  id: number
}

export class RestClient {
  private baseUrl: string
  private headers: Record<string, string>

  constructor(config: RestClientConfig) {
    this.baseUrl = config.baseUrl.replace(/\/$/, '')
    this.headers = config.headers ?? {}
  }

  user = {
    findMany: async (options?: RequestOptions): Promise<User[]> => {
      const response = await fetch(`${this.baseUrl}/users`, {
        method: 'GET',
        headers: { ...this.headers, ...options?.headers },
      })
      if (!response.ok) throw new Error(`GET /users failed: ${response.statusText}`)
      return response.json() as Promise<User[]>
    },

    findUnique: async (where: UserWhereUniqueInput, options?: RequestOptions): Promise<User | null> => {
      const id = where.id
      const response = await fetch(`${this.baseUrl}/users/${id}`, {
        method: 'GET',
        headers: { ...this.headers, ...options?.headers },
      })
      if (response.status === 404) return null
      if (!response.ok) throw new Error(`GET /users/${id} failed: ${response.statusText}`)
      return response.json() as Promise<User>
    },

    create: async (data: UserCreateInput, options?: RequestOptions): Promise<User> => {
      const response = await fetch(`${this.baseUrl}/users`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', ...this.headers, ...options?.headers },
        body: JSON.stringify(data),
      })
      if (!response.ok) throw new Error(`POST /users failed: ${response.statusText}`)
      return response.json() as Promise<User>
    },

    update: async (where: UserWhereUniqueInput, data: UserUpdateInput, options?: RequestOptions): Promise<User> => {
      const id = where.id
      const response = await fetch(`${this.baseUrl}/users/${id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json', ...this.headers, ...options?.headers },
        body: JSON.stringify(data),
      })
      if (!response.ok) throw new Error(`PATCH /users/${id} failed: ${response.statusText}`)
      return response.json() as Promise<User>
    },

    delete: async (where: UserWhereUniqueInput, options?: RequestOptions): Promise<User> => {
      const id = where.id
      const response = await fetch(`${this.baseUrl}/users/${id}`, {
        method: 'DELETE',
        headers: { ...this.headers, ...options?.headers },
      })
      if (!response.ok) throw new Error(`DELETE /users/${id} failed: ${response.statusText}`)
      return response.json() as Promise<User>
    },
  }

  post = {
    // ... same pattern for Post model
  }
}
```

