          primaryKey: null,
        },
      ],
    })

    const code = generateRestClient(dmmf)

    expect(code).toContain('posts?: Post[]')
  })
})

// ---- Test Helpers ----
function createMinimalDmmf(overrides: {
  models?: DMMF.Model[],
  enums?: DMMF.DatamodelEnum[],
}): DMMF.Document {
  return {
    datamodel: {
      models: overrides.models ?? [],
      enums: overrides.enums ?? [],
      types: [],
      indexes: [],
    },
    schema: {
      enumTypes: { prisma: [] },
      inputObjectTypes: { prisma: [] },
      outputObjectTypes: { model: [], prisma: [] },
      fieldRefTypes: {},
    },
    mappings: {
      modelOperations: [],
      otherOperations: { read: [], write: [] },
    },
  }
}

function createScalarField(overrides: Partial<DMMF.Field> & { name: string; type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    name: overrides.name,
    type: overrides.type,
    isRequired: overrides.isRequired ?? true,
    isList: overrides.isList ?? false,
    isUnique: overrides.isUnique ?? false,
    isId: overrides.isId ?? false,
    isReadOnly: overrides.isReadOnly ?? false,
    hasDefaultValue: overrides.hasDefaultValue ?? false,
    ...overrides,
  }
}
