```ts
import fs from 'node:fs'
import path from 'node:path'

import type { GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import { generateRestClient } from './code-generator'

export function onManifest(config: GeneratorConfig): GeneratorManifest {
  return {
    defaultOutput: './generated/rest-client',
    prettyName: 'Prisma REST Client',
  }
}

export async function onGenerate(options: GeneratorOptions): Promise<void> {
  const output = options.generator.output
  if (!output || !output.value) {
    throw new Error('No output directory specified for generator-rest-client')
  }

  const outputDir = output.fromEnvVar
    ? process.env[output.fromEnvVar] ?? output.value
    : output.value

  const code = generateRestClient(options.dmmf)

  fs.mkdirSync(outputDir, { recursive: true })
  fs.writeFileSync(path.join(outputDir, 'rest-client.ts'), code, 'utf-8')
}
```

**Key decisions**:
- `defaultOutput` is `./generated/rest-client` relative to the schema file. This follows the convention of `.prisma/client` used by the main generator, but uses a distinct path.
- The output parsing replicates the pattern from `parseEnvValue` in `@prisma/internals` (line 11-27 of that file) but avoids importing `@prisma/internals` as a dependency, since it is a very heavy package. The env var resolution is simple enough to inline.
- The function writes a single file `rest-client.ts` to the output directory.

