#### 2.8. `packages/generator-rest-client/src/dmmf-helpers.ts`

Utility functions to extract structured data from the DMMF for code generation.

```ts
import type * as DMMF from '@prisma/dmmf'

export interface ParsedField {
  name: string
  tsType: string
  isOptional: boolean
  isList: boolean
  isRelation: boolean
  isId: boolean
  isReadOnly: boolean
  hasDefaultValue: boolean
  kind: DMMF.FieldKind
  documentation?: string
}

export interface ParsedModel {
  name: string
  fields: ParsedField[]
  idField: ParsedField | null
  scalarFields: ParsedField[]
  documentation?: string
}

export interface ParsedEnum {
  name: string
  values: string[]
}

export function parseModels(dmmf: DMMF.Document): ParsedModel[] {
  return dmmf.datamodel.models.map((model) => {
    const fields = model.fields.map(parseField)
    return {
      name: model.name,
      fields,
      idField: fields.find((f) => f.isId) ?? null,
      scalarFields: fields.filter((f) => !f.isRelation),
      documentation: model.documentation,
    }
  })
}

export function parseEnums(dmmf: DMMF.Document): ParsedEnum[] {
  return dmmf.datamodel.enums.map((e) => ({
    name: e.name,
    values: e.values.map((v) => v.name),
  }))
}

function parseField(field: DMMF.Field): ParsedField {
  return {
    name: field.name,
    tsType: field.type,  // resolved later by code-generator using type-mapping
    isOptional: !field.isRequired,
    isList: field.isList,
    isRelation: field.kind === 'object',
    isId: field.isId,
    isReadOnly: field.isReadOnly,
    hasDefaultValue: field.hasDefaultValue,
    kind: field.kind,
    documentation: field.documentation,
  }
}
```

**Key design**: The `parseField` function preserves the raw `field.type` string (e.g., `"String"`, `"Int"`, `"User"`, `"Role"`) in `tsType`. The actual TypeScript type resolution is deferred to `code-generator.ts` which uses `type-mapping.ts` for scalars and references enum/model names directly.

