#### 2.9. `packages/generator-rest-client/src/code-generator.ts`

This is the core module. It takes the parsed DMMF and produces the full `rest-client.ts` file contents as a string.

```ts
import type * as DMMF from '@prisma/dmmf'

import { parseEnums, parseModels, ParsedField, ParsedModel } from './dmmf-helpers'
import { mapScalarType } from './type-mapping'

export function generateRestClient(dmmf: DMMF.Document): string {
  const models = parseModels(dmmf)
  const enums = parseEnums(dmmf)
  const enumNames = new Set(enums.map((e) => e.name))
  const modelNames = new Set(models.map((m) => m.name))

  const parts: string[] = []

  // Header
  parts.push(generateHeader())

  // Enums
  for (const enumDef of enums) {
    parts.push(generateEnum(enumDef))
  }

  // Model interfaces
  for (const model of models) {
    parts.push(generateModelInterface(model, enumNames, modelNames))
  }

  // Create input types (omit id, relations, readOnly fields, fields with defaults)
  for (const model of models) {
    parts.push(generateCreateInput(model, enumNames, modelNames))
  }

  // Update input types (all non-relation scalar fields optional)
  for (const model of models) {
    parts.push(generateUpdateInput(model, enumNames, modelNames))
  }

  // WhereUnique input types (id field only)
  for (const model of models) {
    parts.push(generateWhereUniqueInput(model, enumNames, modelNames))
  }

  // REST client class
  parts.push(generateClientClass(models))

  return parts.join('\n\n')
}
```

Below are the sub-functions. I will detail the signatures and logic for each.

##### `generateHeader()`

```ts
function generateHeader(): string {
  return [
    '// This file was generated by prisma-generator-rest-client. Do not edit manually.',
    '',
    'type RequestOptions = {',
    '  headers?: Record<string, string>',
    '}',
    '',
    'type RestClientConfig = {',
    '  baseUrl: string',
    '  headers?: Record<string, string>',
    '}',
  ].join('\n')
}
```

##### `generateEnum(enumDef)`

```ts
function generateEnum(enumDef: ParsedEnum): string {
  const values = enumDef.values.map((v) => `  ${v} = '${v}'`).join(',\n')
  return `export enum ${enumDef.name} {\n${values}\n}`
}
```

##### `resolveFieldType(field, enumNames, modelNames)`

This is the central type resolution function:

```ts
function resolveFieldType(
  field: ParsedField,
  enumNames: Set<string>,
  modelNames: Set<string>,
): string {
  let tsType: string

  if (field.kind === 'enum') {
    tsType = field.tsType  // use the enum name directly
  } else if (field.kind === 'object') {
    // Relation field — reference the model interface
    tsType = field.tsType
  } else if (field.kind === 'scalar') {
    tsType = mapScalarType(field.tsType)
  } else {
    // 'unsupported'
    tsType = 'unknown'
  }

  if (field.isList) {
    tsType = `${tsType}[]`
  }

  if (field.isOptional) {
    tsType = `${tsType} | null`
  }

  return tsType
}
```

##### `generateModelInterface(model, enumNames, modelNames)`

Generates the full model interface including relation fields:

```ts
function generateModelInterface(
  model: ParsedModel,
  enumNames: Set<string>,
  modelNames: Set<string>,
): string {
  const lines = model.fields.map((field) => {
    const type = resolveFieldType(field, enumNames, modelNames)
    const optionalMark = field.isRelation ? '?' : ''
    const doc = field.documentation ? `  /** ${field.documentation} */\n` : ''
    return `${doc}  ${field.name}${optionalMark}: ${type}`
  })

  const doc = model.documentation ? `/** ${model.documentation} */\n` : ''
  return `${doc}export interface ${model.name} {\n${lines.join('\n')}\n}`
}
```

**Relation field handling**: Relation fields are made optional with `?` on the interface. This is because a REST API response might or might not include related models (they may need a separate request or an `include` parameter). The type reference is the name of the related model's interface directly, so `posts?: Post[]` for a `User` model with a `posts` relation.

##### `generateCreateInput(model, enumNames, modelNames)`

```ts
function generateCreateInput(
  model: ParsedModel,
  enumNames: Set<string>,
  modelNames: Set<string>,
): string {
  const fields = model.fields.filter((f) => {
    // Skip relations, read-only fields, and auto-generated id fields
    if (f.isRelation) return false
    if (f.isReadOnly) return false
    return true
  })

  const lines = fields.map((field) => {
    const type = resolveFieldType(
      { ...field, isOptional: false },
      enumNames,
      modelNames,
    )
    // Fields with defaults or that are optional become optional in CreateInput
    const isOptionalInCreate = field.hasDefaultValue || field.isOptional || field.isId
    const optionalMark = isOptionalInCreate ? '?' : ''
    return `  ${field.name}${optionalMark}: ${type}`
  })

  return `export interface ${model.name}CreateInput {\n${lines.join('\n')}\n}`
}
```

**Rationale**: Fields with `hasDefaultValue` (like auto-increment IDs, `@default(now())`, `@default(uuid())`) are optional in create because the database will supply them. The `isId` check also catches ID fields that have `@default(autoincrement())`. Fields that are `isOptional` (i.e., not `isRequired`) are nullable in the database and therefore optional on create. Relation fields and read-only fields (like foreign key fields marked with `@relation`) are excluded.

##### `generateUpdateInput(model, enumNames, modelNames)`

```ts
function generateUpdateInput(
  model: ParsedModel,
  enumNames: Set<string>,
  modelNames: Set<string>,
): string {
  const fields = model.fields.filter((f) => {
    if (f.isRelation) return false
    if (f.isReadOnly) return false
    if (f.isId) return false
    return true
  })

  const lines = fields.map((field) => {
    const type = resolveFieldType(
      { ...field, isOptional: false },
      enumNames,
      modelNames,
    )
    // All fields optional in update (partial update)
    return `  ${field.name}?: ${type}`
  })

  return `export interface ${model.name}UpdateInput {\n${lines.join('\n')}\n}`
}
```

##### `generateWhereUniqueInput(model, enumNames, modelNames)`

```ts
function generateWhereUniqueInput(
  model: ParsedModel,
  enumNames: Set<string>,
  modelNames: Set<string>,
): string {
  const idField = model.idField
  if (idField) {
    const type = resolveFieldType(
      { ...idField, isOptional: false, isList: false },
      enumNames,
      modelNames,
    )
    return `export interface ${model.name}WhereUniqueInput {\n  ${idField.name}: ${type}\n}`
  }

  // Fallback: if no single @id field, use Record<string, unknown>
  return `export type ${model.name}WhereUniqueInput = Record<string, unknown>`
}
```

##### `generateClientClass(models)`

```ts
function generateClientClass(models: ParsedModel[]): string {
  const modelDelegates = models.map((model) => {
    const name = model.name
    const lowerName = name.charAt(0).toLowerCase() + name.slice(1)
    const pluralName = lowerName + 's'  // simple pluralization

    return `  ${lowerName} = {
    findMany: async (options?: RequestOptions): Promise<${name}[]> => {
      const response = await fetch(\`\${this.baseUrl}/${pluralName}\`, {
        method: 'GET',
        headers: { ...this.headers, ...options?.headers },
      })
      if (!response.ok) throw new Error(\`GET /${pluralName} failed: \${response.statusText}\`)
      return response.json() as Promise<${name}[]>
    },

    findUnique: async (where: ${name}WhereUniqueInput, options?: RequestOptions): Promise<${name} | null> => {
      const id = ${model.idField ? `where.${model.idField.name}` : 'Object.values(where)[0]'}
      const response = await fetch(\`\${this.baseUrl}/${pluralName}/\${id}\`, {
        method: 'GET',
        headers: { ...this.headers, ...options?.headers },
      })
      if (response.status === 404) return null
      if (!response.ok) throw new Error(\`GET /${pluralName}/\${id} failed: \${response.statusText}\`)
      return response.json() as Promise<${name}>
    },

    create: async (data: ${name}CreateInput, options?: RequestOptions): Promise<${name}> => {
      const response = await fetch(\`\${this.baseUrl}/${pluralName}\`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', ...this.headers, ...options?.headers },
        body: JSON.stringify(data),
      })
      if (!response.ok) throw new Error(\`POST /${pluralName} failed: \${response.statusText}\`)
      return response.json() as Promise<${name}>
    },

    update: async (where: ${name}WhereUniqueInput, data: ${name}UpdateInput, options?: RequestOptions): Promise<${name}> => {
      const id = ${model.idField ? `where.${model.idField.name}` : 'Object.values(where)[0]'}
      const response = await fetch(\`\${this.baseUrl}/${pluralName}/\${id}\`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json', ...this.headers, ...options?.headers },
        body: JSON.stringify(data),
      })
      if (!response.ok) throw new Error(\`PATCH /${pluralName}/\${id} failed: \${response.statusText}\`)
      return response.json() as Promise<${name}>
    },

    delete: async (where: ${name}WhereUniqueInput, options?: RequestOptions): Promise<${name}> => {
      const id = ${model.idField ? `where.${model.idField.name}` : 'Object.values(where)[0]'}
      const response = await fetch(\`\${this.baseUrl}/${pluralName}/\${id}\`, {
        method: 'DELETE',
        headers: { ...this.headers, ...options?.headers },
      })
      if (!response.ok) throw new Error(\`DELETE /${pluralName}/\${id} failed: \${response.statusText}\`)
      return response.json() as Promise<${name}>
    },
  }`
  })

  return [
    'export class RestClient {',
    '  private baseUrl: string',
    '  private headers: Record<string, string>',
    '',
    '  constructor(config: RestClientConfig) {',
    '    this.baseUrl = config.baseUrl.replace(/\\/$/, \'\')',
    '    this.headers = config.headers ?? {}',
    '  }',
    '',
    modelDelegates.join('\n\n'),
    '}',
  ].join('\n')
}
```

