/** Produces a block of lines joined by newlines, filtering out any empty strings. */
export function lines(...parts: string[]): string {
  return parts.filter(Boolean).join('\n')
}

/** Indents every line in `text` by `depth × 2` spaces. */
export function indent(text: string, depth = 1): string {
  const pad = '  '.repeat(depth)
  return text
    .split('\n')
    .map((line) => (line.trim() === '' ? '' : `${pad}${line}`))
    .join('\n')
}

/** Wraps `body` inside a TypeScript `interface` declaration. */
export function tsInterface(name: string, body: string): string {
  return `export interface ${name} {\n${indent(body)}\n}`
}

/** Wraps `body` inside a TypeScript `type` alias. */
export function tsType(name: string, body: string): string {
  return `export type ${name} = {\n${indent(body)}\n}`
}

/** Wraps `members` inside a TypeScript `enum` declaration. */
export function tsEnum(name: string, members: string[]): string {
  const body = members.map((m) => `${m} = '${m}',`).join('\n')
  return `export enum ${name} {\n${indent(body)}\n}`
}

