import type * as DMMF from '@prisma/dmmf'

/** Simplified field descriptor used by the code generator. */
export interface ParsedField {
  name: string
  tsType: string
  isRequired: boolean
  isList: boolean
  isId: boolean
  isRelation: boolean
  hasDefault: boolean
  isUpdatedAt: boolean
  isGenerated: boolean
}

/** Simplified model descriptor used by the code generator. */
export interface ParsedModel {
  name: string
  fields: ParsedField[]
  documentation?: string
}

/** Simplified enum descriptor used by the code generator. */
export interface ParsedEnum {
  name: string
  values: string[]
}

/** Extracts models from the DMMF datamodel, filtering out relation fields for the REST client types. */
export function parseModels(datamodel: DMMF.Datamodel): ParsedModel[] {
  return datamodel.models.map((model) => ({
    name: model.name,
    documentation: model.documentation,
    fields: model.fields.map(
      (field): ParsedField => ({
        name: field.name,
        tsType: field.type,
        isRequired: field.isRequired,
        isList: field.isList,
        isId: field.isId,
        isRelation: field.kind === 'object',
        hasDefault: field.hasDefaultValue,
        isUpdatedAt: field.isUpdatedAt ?? false,
        isGenerated: field.isGenerated ?? false,
      }),
    ),
  }))
}

/** Extracts enums from the DMMF datamodel. */
export function parseEnums(datamodel: DMMF.Datamodel): ParsedEnum[] {
  return datamodel.enums.map((e) => ({
    name: e.name,
    values: e.values.map((v) => v.name),
  }))
}

