import type * as DMMF from '@prisma/dmmf'

import { parseEnums, parseModels, type ParsedField, type ParsedModel } from './dmmf-helpers'
import { lines, tsEnum, tsInterface, tsType } from './template'
import { prismaToTsType } from './type-mapping'

/** Generates the full `rest-client.ts` source from a DMMF document. */
export function generate(dmmf: DMMF.Document): string {
  const models = parseModels(dmmf.datamodel)
  const enums = parseEnums(dmmf.datamodel)

  const sections: string[] = [
    fileHeader(),
    ...enums.map(generateEnum),
    ...models.flatMap(generateModelTypes),
    generateRestClientClass(models),
  ]

  return sections.join('\n\n') + '\n'
}

function fileHeader(): string {
  return lines(
    '// This file was generated by @prisma/generator-rest-client. Do not edit manually.',
    '// Re-run `prisma generate` to regenerate.',
    '',
    'type RequestOptions = RequestInit & { params?: Record<string, string> }',
  )
}

function generateEnum(e: { name: string; values: string[] }): string {
  return tsEnum(e.name, e.values)
}

function resolveFieldType(field: ParsedField, forInput: boolean): string {
  if (field.isRelation) {
    return field.isList ? `${field.tsType}[]` : field.tsType
  }

  const base = prismaToTsType(field.tsType)
  const type = field.isList ? `${base}[]` : base
  if (!forInput && !field.isRequired) {
    return `${type} | null`
  }
  return type
}

function scalarFields(model: ParsedModel): ParsedField[] {
  return model.fields.filter((f) => !f.isRelation)
}

function generateModelTypes(model: ParsedModel): string[] {
  const scalars = scalarFields(model)

  const modelInterface = tsInterface(
    model.name,
    scalars.map((f) => `${f.name}: ${resolveFieldType(f, false)};`).join('\n'),
  )

  const createFields = scalars.filter((f) => !f.isGenerated && !f.isUpdatedAt)
  const createInput = tsType(
    `${model.name}CreateInput`,
    createFields.map((f) => `${f.name}${f.hasDefault || !f.isRequired ? '?' : ''}: ${resolveFieldType(f, true)};`).join('\n'),
  )

  const updateInput = tsType(
    `${model.name}UpdateInput`,
    scalars
      .filter((f) => !f.isId && !f.isGenerated)
      .map((f) => `${f.name}?: ${resolveFieldType(f, true)};`)
      .join('\n'),
  )

  const idFields = scalars.filter((f) => f.isId)
  const whereUniqueInput = tsType(
    `${model.name}WhereUniqueInput`,
    idFields.map((f) => `${f.name}: ${resolveFieldType(f, true)};`).join('\n'),
  )

  return [modelInterface, createInput, updateInput, whereUniqueInput]
}

function generateRestClientClass(models: ParsedModel[]): string {
  const methodBlocks = models.map((model) => generateModelMethods(model))

  return lines(
    'export class RestClient {',
    '  #baseUrl: string',
    '',
    '  constructor(baseUrl: string) {',
    '    this.#baseUrl = baseUrl.replace(/\\/$/, \'\')',
    '  }',
    '',
    '  async #request<T>(path: string, options: RequestOptions = {}): Promise<T> {',
    '    const { params, ...init } = options',
    '    let url = `${this.#baseUrl}${path}`',
    '    if (params) {',
    '      const query = new URLSearchParams(params).toString()',
    '      url = `${url}?${query}`',
    '    }',
    '    const response = await fetch(url, {',
    '      ...init,',
    "      headers: { 'Content-Type': 'application/json', ...init.headers },",
    '    })',
    '    if (!response.ok) {',
    '      throw new Error(`REST request failed: ${response.status} ${response.statusText}`)',
    '    }',
    '    return response.json() as Promise<T>',
    '  }',
    '',
    ...methodBlocks,
    '}',
  )
}

function modelPath(model: ParsedModel): string {
  return `/${model.name.toLowerCase()}`
}

function generateModelMethods(model: ParsedModel): string {
  const path = modelPath(model)
  const name = model.name

  return lines(
    `  async ${camelCase(name)}FindMany(options?: RequestOptions): Promise<${name}[]> {`,
    `    return this.#request<${name}[]>('${path}', { ...options, method: 'GET' })`,
    '  }',
    '',
    `  async ${camelCase(name)}FindUnique(where: ${name}WhereUniqueInput, options?: RequestOptions): Promise<${name}> {`,
    `    const id = ${buildIdExpression(model)}`,
    `    return this.#request<${name}>(\`${path}/\${id}\`, { ...options, method: 'GET' })`,
    '  }',
    '',
    `  async ${camelCase(name)}Create(data: ${name}CreateInput, options?: RequestOptions): Promise<${name}> {`,
    `    return this.#request<${name}>('${path}', { ...options, method: 'POST', body: JSON.stringify(data) })`,
    '  }',
    '',
    `  async ${camelCase(name)}Update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput, options?: RequestOptions): Promise<${name}> {`,
    `    const id = ${buildIdExpression(model)}`,
    `    return this.#request<${name}>(\`${path}/\${id}\`, { ...options, method: 'PATCH', body: JSON.stringify(data) })`,
    '  }',
    '',
    `  async ${camelCase(name)}Delete(where: ${name}WhereUniqueInput, options?: RequestOptions): Promise<${name}> {`,
    `    const id = ${buildIdExpression(model)}`,
    `    return this.#request<${name}>(\`${path}/\${id}\`, { ...options, method: 'DELETE' })`,
    '  }',
    '',
  )
}

function buildIdExpression(model: ParsedModel): string {
  const idFields = scalarFields(model).filter((f) => f.isId)
  if (idFields.length === 0) {
    // Fallback: use a field named "id" if present, otherwise first field
    return "where[Object.keys(where)[0] as keyof typeof where]"
  }
  if (idFields.length === 1) {
    return `where.${idFields[0].name}`
  }
  // Composite key: join with underscore
  return `[${idFields.map((f) => `where.${f.name}`).join(', ')}].join('_')`
}

function camelCase(name: string): string {
  return name.charAt(0).toLowerCase() + name.slice(1)
}

