import { describe, expect, test } from 'vitest'

import { prismaToTsType } from '../type-mapping'

describe('prismaToTsType', () => {
  test.each([
    ['String', 'string'],
    ['Boolean', 'boolean'],
    ['Int', 'number'],
    ['Float', 'number'],
    ['BigInt', 'bigint'],
    ['Decimal', 'string'],
    ['DateTime', 'Date'],
    ['Json', 'unknown'],
    ['Bytes', 'Buffer'],
  ])('maps %s to %s', (prisma, expected) => {
    expect(prismaToTsType(prisma)).toBe(expected)
  })

  test('falls back to string for unknown types', () => {
    expect(prismaToTsType('UnknownType')).toBe('string')
  })
})

