import { describe, expect, test } from 'vitest'

import { generate } from '../generator'

function makeDmmf(models: any[] = [], enums: any[] = []) {
  return {
    datamodel: {
      models,
      enums,
      types: [],
      indexes: [],
    },
    schema: {
      inputObjectTypes: {},
      outputObjectTypes: { model: [], prisma: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: {},
    },
    mappings: {
      modelOperations: [],
      otherOperations: { read: [], write: [] },
    },
  }
}

function makeField(overrides: Partial<any> = {}) {
  return {
    name: 'id',
    kind: 'scalar' as const,
    type: 'Int',
    isRequired: true,
    isList: false,
    isUnique: true,
    isId: true,
    isReadOnly: false,
    hasDefaultValue: true,
    isGenerated: false,
    isUpdatedAt: false,
    ...overrides,
  }
}

function makeModel(name: string, fields: any[]) {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  }
}

describe('generate', () => {
  test('produces valid output for a simple model', () => {
    const dmmf = makeDmmf([
      makeModel('User', [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'email', type: 'String', isId: false, isUnique: true, hasDefaultValue: false }),
        makeField({ name: 'name', type: 'String', isId: false, isRequired: false, hasDefaultValue: false }),
      ]),
    ])

    const output = generate(dmmf as any)

    expect(output).toContain('export interface User')
    expect(output).toContain('id: number;')
    expect(output).toContain('email: string;')
    expect(output).toContain('name: string | null;')

    expect(output).toContain('export type UserCreateInput')
    expect(output).toContain('id?: number;')
    expect(output).toContain('email: string;')

    expect(output).toContain('export type UserUpdateInput')

    expect(output).toContain('export type UserWhereUniqueInput')

    expect(output).toContain('export class RestClient')
    expect(output).toContain('userFindMany')
    expect(output).toContain('userFindUnique')
    expect(output).toContain('userCreate')
    expect(output).toContain('userUpdate')
    expect(output).toContain('userDelete')
  })

  test('generates enums', () => {
    const dmmf = makeDmmf(
      [
        makeModel('User', [
          makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
          makeField({ name: 'role', type: 'Role', kind: 'enum', isId: false, hasDefaultValue: false }),
        ]),
      ],
      [{ name: 'Role', values: [{ name: 'ADMIN', dbName: null }, { name: 'USER', dbName: null }] }],
    )

    const output = generate(dmmf as any)

    expect(output).toContain('export enum Role')
    expect(output).toContain("ADMIN = 'ADMIN',")
    expect(output).toContain("USER = 'USER',")
  })

  test('excludes relation fields from model interface', () => {
    const dmmf = makeDmmf([
      makeModel('Post', [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'title', type: 'String', isId: false, hasDefaultValue: false }),
        makeField({ name: 'author', kind: 'object', type: 'User', isId: false, hasDefaultValue: false }),
        makeField({ name: 'authorId', type: 'Int', isId: false, hasDefaultValue: false, isReadOnly: true }),
      ]),
    ])

    const output = generate(dmmf as any)

    expect(output).toContain('export interface Post')
    expect(output).toContain('title: string;')
    expect(output).toContain('authorId: number;')
    expect(output).not.toContain('author: User;')
  })

  test('excludes isGenerated and isUpdatedAt fields from create input', () => {
    const dmmf = makeDmmf([
      makeModel('User', [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true, isGenerated: true }),
        makeField({ name: 'name', type: 'String', isId: false, hasDefaultValue: false }),
        makeField({ name: 'updatedAt', type: 'DateTime', isId: false, hasDefaultValue: false, isUpdatedAt: true }),
      ]),
    ])

    const output = generate(dmmf as any)

    // The CreateInput should not include generated or updatedAt fields
    const createInputBlock = output.slice(output.indexOf('export type UserCreateInput'))
    const createInputEnd = createInputBlock.indexOf('}')
    const createInput = createInputBlock.slice(0, createInputEnd + 1)
    expect(createInput).not.toContain('updatedAt')
    // id is generated, should be excluded from create
    expect(createInput).not.toMatch(/^\s*id\b/m)
  })

  test('produces file header comment', () => {
    const dmmf = makeDmmf()
    const output = generate(dmmf as any)
    expect(output).toContain('Do not edit manually')
  })

  test('handles multiple models', () => {
    const dmmf = makeDmmf([
      makeModel('User', [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      ]),
      makeModel('Post', [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'title', type: 'String', isId: false, hasDefaultValue: false }),
      ]),
    ])

    const output = generate(dmmf as any)

    expect(output).toContain('export interface User')
    expect(output).toContain('export interface Post')
    expect(output).toContain('userFindMany')
    expect(output).toContain('postFindMany')
  })
})

