import { describe, expect, test } from 'vitest'

import { indent, lines, tsEnum, tsInterface, tsType } from '../template'

describe('lines', () => {
  test('joins non-empty strings with newlines', () => {
    expect(lines('a', 'b', 'c')).toBe('a\nb\nc')
  })

  test('filters out empty strings', () => {
    expect(lines('a', '', 'c')).toBe('a\nc')
  })
})

describe('indent', () => {
  test('indents by 2 spaces by default', () => {
    expect(indent('foo')).toBe('  foo')
  })

  test('indents by specified depth', () => {
    expect(indent('foo', 2)).toBe('    foo')
  })

  test('preserves empty lines as-is', () => {
    expect(indent('a\n\nb')).toBe('  a\n\n  b')
  })
})

describe('tsInterface', () => {
  test('wraps body in an interface declaration', () => {
    const result = tsInterface('Foo', 'bar: string;')
    expect(result).toBe('export interface Foo {\n  bar: string;\n}')
  })
})

describe('tsType', () => {
  test('wraps body in a type alias', () => {
    const result = tsType('Foo', 'bar: string;')
    expect(result).toBe('export type Foo = {\n  bar: string;\n}')
  })
})

describe('tsEnum', () => {
  test('generates an enum declaration', () => {
    const result = tsEnum('Role', ['ADMIN', 'USER'])
    expect(result).toContain('export enum Role {')
    expect(result).toContain("ADMIN = 'ADMIN',")
    expect(result).toContain("USER = 'USER',")
  })
})

